INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '756f5520-3ca1-4774-9500-a2a6eefd62e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch Training Loop — Forward Pass to Optimizer Step$escape$,
  $escape$Every PyTorch training iteration follows a strict four-step rhythm. First, the forward pass: call `model(inputs)` to compute predictions — PyTorch builds a dynamic computation graph on-the-fly via autograd. Second, compute loss using a criterion like `nn.CrossEntropyLoss()(outputs, targets)`. Third, backpropagation: call `loss.backward()`, which traverses the computation graph in reverse and accumulates gradients into each parameter's `.grad` attribute. Fourth, `optimizer.step()` applies those gradients to update weights using the rule defined by your optimizer (SGD, Adam, etc.).

Critically, `optimizer.zero_grad()` must be called before `loss.backward()` — PyTorch accumulates gradients by default, so skipping this causes gradients from previous batches to bleed into the current update. Set `set_to_none=True` for a small memory win. For mixed-precision training, wrap the forward pass in `torch.autocast` and replace `loss.backward()` + `optimizer.step()` with `scaler.scale(loss).backward()` + `scaler.step(optimizer)` using a `GradScaler`.$escape$,
  $escape$import torch
import torch.nn as nn

model.train()
optimizer = torch.optim.AdamW(model.parameters(), lr=3e-4)
criterion = nn.CrossEntropyLoss()

for inputs, targets in dataloader:
    inputs, targets = inputs.to(device), targets.to(device)

    optimizer.zero_grad(set_to_none=True)  # clear stale gradients
    outputs = model(inputs)                # forward pass + graph build
    loss = criterion(outputs, targets)     # scalar loss tensor
    loss.backward()                        # backprop: populate .grad
    torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
    optimizer.step()                       # weight update$escape$,
  $escape$python$escape$,
