INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '56e98a83-a108-45fb-bd78-64459b0d9b75',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch DataLoader — Batching, Shuffling, Prefetching, and Augmentation Done Right$escape$,
  $escape$PyTorch's `DataLoader` wraps any `Dataset` and handles the heavy lifting of batching, shuffling, and parallel data loading. Set `num_workers > 0` to spawn worker processes that prefetch batches while the GPU trains — on Linux, `num_workers=4` is a safe default; on Windows, wrap your script in `if __name__ == '__main__'` to avoid multiprocessing errors. `pin_memory=True` allocates batches in page-locked memory, making `.to(device)` transfers faster when using CUDA. Enable `persistent_workers=True` to keep worker processes alive across epochs, cutting per-epoch startup overhead.

For augmentation, apply transforms inside `__getitem__` using `torchvision.transforms.v2` (the updated API that handles bounding boxes and masks). Avoid heavy transforms in the main process — workers parallelize them for free. Use `prefetch_factor` (default 2) to control how many batches each worker prepopulates. For variable-length sequences, pass a custom `collate_fn` to `DataLoader` instead of relying on the default, which will error on ragged tensors. Combine `drop_last=True` with `shuffle=True` to prevent a partial final batch from skewing batch norm statistics.$escape$,
  $escape$from torch.utils.data import DataLoader, Dataset
from torchvision.transforms import v2

class MyDataset(Dataset):
    def __init__(self, data, transforms=None):
        self.data = data
        self.transforms = transforms

    def __len__(self): return len(self.data)

    def __getitem__(self, idx):
        img, label = self.data[idx]
        if self.transforms:
            img = self.transforms(img)
        return img, label

transforms = v2.Compose([v2.RandomHorizontalFlip(), v2.ToDtype(torch.float32, scale=True)])
dataset = MyDataset(raw_data, transforms=transforms)

loader = DataLoader(
    dataset,
    batch_size=64,
    shuffle=True,
    num_workers=4,
    pin_memory=True,
    persistent_workers=True,
    drop_last=True,
)$escape$,
  $escape$python$escape$,
