INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '68355274-8076-4be5-8342-c330a86287f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$PyTorch Regularization — Dropout, Weight Decay, BatchNorm, and Early Stopping in Practice$escape$,
  $escape$PyTorch gives you four complementary regularization tools, each targeting a different failure mode. `nn.Dropout(p=0.5)` randomly zeroes activations during training — call `model.train()` and `model.eval()` to toggle it correctly, or it'll silently apply at inference. Weight decay is passed directly to the optimizer: `torch.optim.AdamW(model.parameters(), lr=1e-3, weight_decay=1e-4)` — prefer `AdamW` over `Adam + L2` since Adam's adaptive scaling makes raw L2 ineffective. `nn.BatchNorm1d` / `nn.BatchNorm2d` normalizes per-batch activations and carries its own learnable `weight` and `bias` parameters; it also behaves differently under `train()` vs `eval()` (running stats vs batch stats). Early stopping isn't built-in — track validation loss manually and checkpoint with `torch.save(model.state_dict(), 'best.pt')`, restoring via `model.load_state_dict(torch.load('best.pt'))` when patience expires. Combine all four: BatchNorm before activation, Dropout after, AdamW with decay, early stopping on val loss.$escape$,
  $escape$import torch
import torch.nn as nn

class RegularizedNet(nn.Module):
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(128, 64),
            nn.BatchNorm1d(64),
            nn.ReLU(),
            nn.Dropout(p=0.4),
            nn.Linear(64, 10)
        )

    def forward(self, x):
        return self.net(x)

model = RegularizedNet()
optimizer = torch.optim.AdamW(model.parameters(), lr=1e-3, weight_decay=1e-4)

best_val_loss = float('inf')
patience, strikes = 5, 0

for epoch in range(100):
    model.train()
    # ... training loop ...

    model.eval()
    with torch.no_grad():
        val_loss = compute_val_loss()  # your validation logic

    if val_loss < best_val_loss:
        best_val_loss = val_loss
        strikes = 0
        torch.save(model.state_dict(), 'best.pt')
    else:
        strikes += 1
        if strikes >= patience:
            model.load_state_dict(torch.load('best.pt'))
            break$escape$,
  $escape$python$escape$,
